const day = new Date().toISOString().slice(0,10);document.getElementById('day').textContent=day;const AL='ABCDEFGHIJKLMNOPQRSTUVWXYZ';const WORDS=['GAME','MATH','WORD','LENS','PLAY','CLUE','CARD','TILE','WINS','DUEL'];let seed=[...day].reduce((a,c)=>a*31+c.charCodeAt(0),7)>>>0;const rnd=()=>((seed=seed*1664525+1013904223>>>0)/2**32);let hand=[],slots=['','','',''],score=0,usedSwap=false;const h=document.getElementById('hand'),b=document.getElementById('board'),msg=document.getElementById('msg');function loadStats(){document.getElementById('streak').textContent=localStorage.getItem('wsm_streak')||0;document.getElementById('best').textContent=localStorage.getItem('wsm_best')||0;}function draw(){if(hand.length>=7)return;hand.push(AL[Math.floor(rnd()*26)]);render();}function render(){h.innerHTML='';hand.forEach((c,i)=>{const d=document.createElement('button');d.className='tile';d.textContent=c;d.onclick=()=>place(i);h.appendChild(d)});b.innerHTML='';slots.forEach((c,i)=>{const d=document.createElement('button');d.className='slot';d.textContent=c||'+';d.onclick=()=>remove(i);b.appendChild(d)});}function place(i){const s=slots.indexOf('');if(s<0){msg.textContent='Slots full';return;}slots[s]=hand.splice(i,1)[0];render();}function remove(i){if(!slots[i])return;if(usedSwap){msg.textContent='Solitaire rule: only one slot clear per turn';return;}hand.push(slots[i]);slots[i]='';usedSwap=true;render();}function end(win){const st=Number(localStorage.getItem('wsm_streak')||0);const todayDone=localStorage.getItem('wsm_day');const nst=win&&todayDone!==day?st+1:win?st:0;localStorage.setItem('wsm_streak',String(nst));localStorage.setItem('wsm_day',day);const best=Math.max(Number(localStorage.getItem('wsm_best')||0),score);localStorage.setItem('wsm_best',String(best));const text=`Word-Solitaire Mix\nDate: ${day}\nResult: ${win?'WIN':'LOSE'}\nScore: ${score}\nStreak: ${nst}`;document.getElementById('share').textContent=text;document.getElementById('result').classList.remove('hidden');loadStats();}
document.getElementById('draw').onclick=()=>{usedSwap=false;draw();};document.getElementById('clear').onclick=()=>{slots=['','','',''];usedSwap=false;render();};document.getElementById('submit').onclick=()=>{const w=slots.join('');if(w.length<4||w.includes('')){msg.textContent='Fill 4 slots';return;}if(WORDS.includes(w)){score+=100;msg.textContent=`Nice: ${w} (+100)`;if(score>=300)end(true);}else{msg.textContent=`${w} not in today list`;end(false);}slots=['','','',''];usedSwap=false;render();};document.getElementById('copy').onclick=()=>navigator.clipboard.writeText(document.getElementById('share').textContent);document.getElementById('again').onclick=()=>location.reload();loadStats();for(let i=0;i<5;i++)draw();render();